async (params, browser) => {
  // Open question
  await browser.open(`${params.question_url}`)

  // Wait for answers
  await browser.waitForSelector('[class*=\'Answer\'], [class*=\'answer\']', 15000)

  await browser.wait(2000)

  // Scroll for answers
  await browser.scroll({ direction: 'down', amount: 2000 })

  await browser.wait(2000)

  // Scroll more
  await browser.scroll({ direction: 'down', amount: 2000 })

  await browser.wait(2000)

  // Scroll further
  await browser.scroll({ direction: 'down', amount: 2000 })

  await browser.wait(1500)

  // Extract detailed answers
  const answers_data = await browser.evaluate(`const questionEl = document.querySelector('[class*="question_text"], h1'); const answers = []; const answerEls = document.querySelectorAll('[class*="Answer"], [class*="answer"][class*="base"]'); for (let i = 0; i < Math.min(answerEls.length, 15); i++) { const el = answerEls[i]; const authorEl = el.querySelector('[class*="user"] a, [class*="author"] a'); const credentialEl = el.querySelector('[class*="credential"]'); const contentEl = el.querySelector('[class*="inline"], [class*="answer-content"]'); const upvotesEl = el.querySelector('[class*="upvote"] [class*="count"]'); const commentsEl = el.querySelector('[class*="comment"] [class*="count"]'); const sharesEl = el.querySelector('[class*="share"] [class*="count"]'); answers.push({ author: authorEl ? authorEl.textContent.trim() : '', credential: credentialEl ? credentialEl.textContent.trim() : '', content: contentEl ? contentEl.textContent.trim().substring(0, 2000) : '', upvotes: upvotesEl ? upvotesEl.textContent.trim() : '', comments: commentsEl ? commentsEl.textContent.trim() : '', shares: sharesEl ? sharesEl.textContent.trim() : '' }); } return { question: questionEl ? questionEl.textContent.trim() : '', answer_count: answers.length, answers: answers, url: window.location.href }`)

  return answers_data
}
